mapper.select:
SELECT m.menu_id, m.sys_se_cd, m.menu_nm, m.upper_menu_id, m.menu_ord, m.prgrm_id, m.icon_nm, m.use_bgng_dt, m.use_end_dt, m.frst_reg_dt, m.frst_reg_user_id, m.last_chg_dt, m.last_chg_user_id, p.prgrm_url, p.api_path_prefix FROM com.tn_sys_menu m LEFT JOIN com.tn_prgrm p ON p.prgrm_id = m.prgrm_id AND NOW() BETWEEN p.use_bgng_dt AND p.use_end_dt WHERE NOW() BETWEEN m.use_bgng_dt AND m.use_end_dt
AND m.sys_se_cd = #{sysSeCd}
ORDER BY m.menu_ord ASC, m.menu_id ASC

SELECT EXISTS(
    SELECT 1
      FROM com.tn_sys_menu
     WHERE menu_id = #{menuId}
)

mapper.update:
UPDATE com.tn_sys_menu
   SET use_end_dt      = NOW() - INTERVAL '1 minute',
       last_chg_dt     = NOW(),
       last_chg_user_id = #{userId}
 WHERE menu_id = #{menuId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
